// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.text = "#### Lunch Command Help\n" +
                      "Need help with `/lunch`? Here are the available options:\n\n" +
                      "| Command | Description | Visibility |\n" +
                      "| :--- | :--- | :--- |\n" +
                      "| `/lunch` | Displays today's lunch menu | Public (In Channel) |\n" +
                      "| `/lunch list` | Lists all your active food notifications | Private (Only You) |\n" +
                      "| `/lunch sub [diet] [keyword]` | Create a notification. Diet options: `all`, `veggie`, `vegan` | Private (Only You) |\n" +
                      "| `/lunch unsub [keyword]` | Delete a notification | Private (Only You) |\n" +
                      "| `/lunch help` | Displays this help menu | Private (Only You) |\n\n" + 
                      "💡 *Tip: If your keyword has spaces, wrap it in quotes. Example:* `/lunch notify veggie \"chili sin carne\"`";

  item.json.attachments = [
    {
        text: "💡 **Quick Actions:** Don't want to type? Click a shortcut below:",
        actions: [
            {
                id: "helpactionmenu",
                name: "📋 Show Today's Menu",
                type: "button",
                style: "primary", // Blue button
                integration: {
                    url: item.json.webhook_url, // Your n8n webhook
                    context: {
                        action: "menu_click"
                    }
                }
            },
            {
                id: "helpactionlist",
                name: "🔔 View My Active Alerts",
                type: "button",
                style: "default", // Standard button
                integration: {
                    url: item.json.webhook_url, // Your n8n webhook
                    context: {
                        action: "list_click"
                    }
                }
            }
        ]
    }
  ];
}

return $input.all();
